def jogo_da_vida():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    Q = int(data[1])

    grid = []
    index = 2
    for i in range(N):
        row = list(data[index])
        grid.append([int(c) for c in row])
        index += 1

    for _ in range(Q):
        new_grid = [[0]*N for _ in range(N)]
        for i in range(N):
            for j in range(N):
                vivas = 0
                for di in (-1, 0, 1):
                    for dj in (-1, 0, 1):
                        if di == 0 and dj == 0:
                            continue
                        ni, nj = i + di, j + dj
                        if 0 <= ni < N and 0 <= nj < N:
                            vivas += grid[ni][nj]
                if grid[i][j] == 1:
                    if vivas == 2 or vivas == 3:
                        new_grid[i][j] = 1
                else:
                    if vivas == 3:
                        new_grid[i][j] = 1
        grid = new_grid

    for row in grid:
        print(''.join(map(str, row)))

jogo_da_vida()
